using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int x[MAXN],y[MAXN],n,m,buyone[MAXN],buymany[MAXN],sum=0,ans=0;
signed main(void)
{
    // freopen("in.txt","r",stdin);
    // freopen("out.txt","w",stdout);
	n=read(),m=read();
	FOR(i,1,n)
	{
		x[i]=read();
		y[i]=read();
	}
	FOR(i,1,n)
	{
		buyone[i]=x[i];
		buymany[i]=x[i]+y[i];
	}
	sort(buyone+1,buyone+n+1);
	sort(buymany+1,buymany+n+1);
	ans=(m/buymany[1])*2;
	FOR(i,1,n)
	{
		sum+=buyone[i];
		ans=max(ans,((m-sum)/buymany[1]*2)+(m>=sum)*i);
	}
	cout<<ans;
    return false;
}
